begin
wwv_flow_imp_page.create_page(
 p_id=>2
,p_name=>'Detalle Bar'
,p_alias=>'DETALLE-BAR'
,p_step_title=>'Detalle Bar'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://taller3-fbd-76uh.onrender.com/bares'';',
'const barId = parseInt(apex.item(''P_BAR_ID'').getValue());',
'',
'console.log(''API_BASE:'', API_BASE);',
'console.log(''barId:'', barId);',
'',
'function cargarDetalleBar() {',
'  const url = `${API_BASE}/${barId}`;',
'  console.log(''Cargando detalle bar desde:'', url);',
'',
'  fetch(url)',
'    .then(async res => {',
'      const text = await res.text();',
'      console.log(''Respuesta cruda detalle bar:'', text);',
'',
'      if (!res.ok) {',
'        throw new Error(`HTTP ${res.status} - ${text}`);',
'      }',
'',
'      if (!text || !text.trim()) {',
unistr('        throw new Error(''Respuesta vac\00EDa del bar.'');'),
'      }',
'',
'      return JSON.parse(text);',
'    })',
'    .then(bar => {',
'      const container = document.getElementById(''detalle-bar-container'');',
'',
'      container.innerHTML = `',
'        <div style="border:1px solid #ddd; border-radius:10px; padding:16px; margin-bottom:16px;">',
'          <h2 style="margin-top:0;">${bar.nombre || ''Sin nombre''}</h2>',
'          <p><strong>Ciudad:</strong> ${bar.ciudad || ''No disponible''}</p>',
unistr('          <p><strong>Direcci\00F3n:</strong> ${bar.direccion || ''No disponible''}</p>'),
'          <p><strong>Tipo:</strong> ${bar.tipo || ''No disponible''}</p>',
unistr('          <p><strong>Descripci\00F3n:</strong> ${bar.descripcion || ''No disponible''}</p>'),
'        </div>',
'      `;',
'    })',
'    .catch(err => {',
'      console.error(''Error cargando detalle del bar:'', err);',
'      document.getElementById(''detalle-bar-container'').innerHTML =',
'        `<p style="color:red;">Error cargando detalle del bar: ${err.message}</p>`;',
'    });',
'}',
'',
'function cargarComentarios() {',
'  const url = `${API_BASE}/${barId}/comentarios`;',
'  console.log(''Cargando comentarios desde:'', url);',
'',
'  fetch(url)',
'    .then(async res => {',
'      console.log(''Status comentarios GET:'', res.status);',
'',
'      const text = await res.text();',
'      console.log(''Respuesta cruda comentarios:'', text);',
'',
'      if (!res.ok) {',
'        throw new Error(`HTTP ${res.status} - ${text}`);',
'      }',
'',
'      if (!text || !text.trim()) {',
'        return [];',
'      }',
'',
'      return JSON.parse(text);',
'    })',
'    .then(data => {',
'      console.log(''Comentarios recibidos:'', data);',
'      const container = document.getElementById(''comentarios-container'');',
'',
'      if (!data.length) {',
unistr('        container.innerHTML = ''<p>No hay comentarios a\00FAn. \00A1S\00E9 el primero!</p>'';'),
'        return;',
'      }',
'',
'      container.innerHTML = data.map(c => `',
'        <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
unistr('          <strong>${c.autor || ''An\00F3nimo''}</strong>'),
'          <span style="color:#888; font-size:0.85em; margin-left:10px;">',
'            ${c.date ? new Date(c.date).toLocaleDateString(''es-CO'') : ''''}',
'          </span>',
'          <p style="margin-top:6px;">${c.texto || ''''}</p>',
'        </div>',
'      `).join('''');',
'    })',
'    .catch(err => {',
'      console.error(''Error cargando comentarios:'', err);',
'      document.getElementById(''comentarios-container'').innerHTML =',
'        `<p style="color:red;">Error cargando comentarios: ${err.message}</p>`;',
'    });',
'}',
'',
'function enviarComentario() {',
'  const texto = apex.item(''P_COMENTARIO'').getValue();',
'  const url = `${API_BASE}/${barId}/comentarios`;',
'',
'  console.log(''Enviando comentario a:'', url);',
'',
'  if (!texto.trim()) {',
'    apex.message.showErrors([{',
'      type: "error",',
'      location: ["page"],',
unistr('      message: "El comentario no puede estar vac\00EDo.",'),
'      unsafe: false',
'    }]);',
'    return;',
'  }',
'',
'  fetch(url, {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify({',
'      bar_id: parseInt(barId),',
'      texto: texto,',
'      autor: apex.env.APP_USER',
'    })',
'  })',
'    .then(async res => {',
'      const text = await res.text();',
'      console.log(''Status comentario POST:'', res.status);',
'      console.log(''Respuesta cruda comentario POST:'', text);',
'',
'      if (!res.ok) {',
'        throw new Error(`HTTP ${res.status} - ${text}`);',
'      }',
'',
'      return text ? JSON.parse(text) : {};',
'    })',
'    .then(() => {',
'      apex.item(''P_COMENTARIO'').setValue('''');',
'      cargarComentarios();',
'    })',
'    .catch(err => {',
'      console.error(''Error enviando comentario:'', err);',
'      apex.message.showErrors([{',
'        type: "error",',
'        location: ["page"],',
'        message: `Error enviando el comentario: ${err.message}`,',
'        unsafe: false',
'      }]);',
'    });',
'}',
'',
'function cargarEventos() {',
'  const url = `${API_BASE}/${barId}/eventos`;',
'  console.log(''Cargando eventos desde:'', url);',
'',
'  fetch(url)',
'    .then(async res => {',
'      const text = await res.text();',
'      console.log(''Respuesta cruda eventos:'', text);',
'',
'      if (!res.ok) {',
'        throw new Error(`HTTP ${res.status} - ${text}`);',
'      }',
'',
'      if (!text || !text.trim()) {',
'        return [];',
'      }',
'',
'      return JSON.parse(text);',
'    })',
'    .then(data => {',
'      const container = document.getElementById(''eventos-container'');',
'',
'      if (!data.length) {',
'        container.innerHTML = ''<p>No hay eventos registrados.</p>'';',
'        return;',
'      }',
'',
'      container.innerHTML = data.map(e => `',
'        <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
'          <strong>${e.nombre || ''Sin nombre''}</strong>',
'          <div style="color:#666; margin-top:4px;">',
'            ${e.fecha ? new Date(e.fecha).toLocaleDateString(''es-CO'') : ''''}',
'          </div>',
'          <p style="margin-top:6px;">${e.descripcion || ''''}</p>',
'        </div>',
'      `).join('''');',
'    })',
'    .catch(err => {',
'      console.error(''Error cargando eventos:'', err);',
'      document.getElementById(''eventos-container'').innerHTML =',
'        `<p style="color:red;">Error cargando eventos: ${err.message}</p>`;',
'    });',
'}',
'',
'function crearEvento() {',
'  const nombre = apex.item(''P_EVENTO_NOMBRE'').getValue();',
'  const fecha = apex.item(''P_EVENTO_FECHA'').getValue();',
'  const descripcion = apex.item(''P_EVENTO_DESCRIPCION'').getValue();',
'  const url = `${API_BASE}/${barId}/eventos`;',
'',
'  if (!nombre.trim()) {',
'    apex.message.showErrors([{',
'      type: "error",',
'      location: ["page"],',
'      message: "El nombre del evento es obligatorio.",',
'      unsafe: false',
'    }]);',
'    return;',
'  }',
'',
'  fetch(url, {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify({',
'      bar_id: parseInt(barId),',
'      nombre: nombre,',
'      fecha: fecha,',
'      descripcion: descripcion',
'    })',
'  })',
'    .then(async res => {',
'      const text = await res.text();',
'      console.log(''Status evento POST:'', res.status);',
'      console.log(''Respuesta cruda evento POST:'', text);',
'',
'      if (!res.ok) {',
'        throw new Error(`HTTP ${res.status} - ${text}`);',
'      }',
'',
'      return text ? JSON.parse(text) : {};',
'    })',
'    .then(() => {',
'      apex.item(''P_EVENTO_NOMBRE'').setValue('''');',
'      apex.item(''P_EVENTO_FECHA'').setValue('''');',
'      apex.item(''P_EVENTO_DESCRIPCION'').setValue('''');',
'      cargarEventos();',
'    })',
'    .catch(err => {',
'      console.error(''Error creando evento:'', err);',
'      apex.message.showErrors([{',
'        type: "error",',
'        location: ["page"],',
'        message: `Error creando evento: ${err.message}`,',
'        unsafe: false',
'      }]);',
'    });',
'}',
'',
'cargarDetalleBar();',
'cargarComentarios();',
'cargarEventos();'))
